function getBizCompositions(string $bizType): array {
    global $BIZ_COMPOSITIONS;
    if (isset($BIZ_COMPOSITIONS[$bizType])) return $BIZ_COMPOSITIONS[$bizType];
    $text = mb_strtolower(trim($bizType));
    $bestKey = null; $bestScore = 0;
    foreach ($BIZ_COMPOSITIONS as $key => $data) {
        $kt = mb_strtolower($key);
        if ($kt === $text) return $data;
        $score = 0;
        if (mb_strpos($kt, $text) !== false || mb_strpos($text, $kt) !== false) $score = mb_strlen($kt);
        else {
            foreach (preg_split('/[\s\-\/,]+/u', $text) as $w) {
                if (mb_strlen($w) < 3) continue;
                foreach (preg_split('/[\s\-\/,]+/u', $kt) as $kw) {
                    if ($w === $kw) $score += 3;
                    elseif (mb_strpos($kw, $w) !== false) $score += 1;
                }
            }
        }
        if ($score > $bestScore) { $bestScore = $score; $bestKey = $key; }
    }
    return ($bestKey && $bestScore >= 2) ? $BIZ_COMPOSITIONS[$bestKey] : $BIZ_COMPOSITIONS['Магазин за дамски дрехи'];
}
